161	          return `${filter.def.name} ${t('contains')}`;
162	      }
163	    },
164	    [t]
165	  );
166	
167	  const getFilterDisplay = React.useCallback(
168	    (filter: Filter, cfIndex: number) => {
169	      const someEnabled = hasEnabledFilterValues(filter);
170	      return (
171	        <div key={cfIndex} className={`${filter.def.category ? 'flex-block' : ''} toolbar-item-center`}>
172	          {getAndOr(filters.match, cfIndex)}
173	          <div className={`custom-chip-group ${someEnabled ? '' : 'disabled-group'}`}>
174	            <Tooltip
175	              content={`${someEnabled ? t('Disable') : t('Enable')} '${getFullName(filter)}' ${t('group filter')}`}
176	            >
177	              <Text
178	                className="custom-chip-text"
179	                component={TextVariants.p}
180	                onClick={() => {
181	                  //switch all values if no remaining
182	                  filter.values.forEach(fv => {
183	                    fv.disabled = someEnabled;
184	                  });
185	                  setFilters(_.cloneDeep(filters));
186	                }}
187	              >
188	                {getFullName(filter)}
189	              </Text>
190	            </Tooltip>
191	            <div className="filtervalues">
192	              {filter.values.map((filterValue, fvIndex) => {
193	                if (isForced || filterValue.disabled) {
194	                  return (
195	                    <div key={fvIndex} className={`flex-block ${fvIndex == 0 ? 'first' : ''}`}>
196	                      {getAndOr('values', fvIndex)}
197	                      <div className={`custom-chip ${filterValue.disabled ? 'disabled-value' : ''}`}>
198	                        <Tooltip
199	                          content={`${filterValue.disabled ? t('Enable') : t('Disable')} ${getFullName(filter)} '${
200	                            filterValue.display || filterValue.v
201	                          }' ${t('filter')}`}
202	                        >
203	                          <Text
204	                            component={TextVariants.p}
205	                            onClick={() => {
206	                              filterValue.disabled = !filterValue.disabled;
207	                              setFilters(_.cloneDeep(filters));
208	                            }}
209	                          >
210	                            {filterValue.display ? filterValue.display : filterValue.v}
211	                          </Text>
212	                        </Tooltip>
213	                      </div>
214	                    </div>
215	                  );
216	                }
217	
218	                const dropdownId = `${filter.def.id}-${fvIndex}`;
219	                return (
220	                  <div key={fvIndex} className={`flex-block ${fvIndex == 0 ? 'first' : ''}`}>
221	                    {getAndOr('values', fvIndex)}
222	                    <Dropdown
223	                      id={dropdownId}
224	                      data-test={dropdownId}
225	                      isOpen={dropdownId === openedDropdown}
226	                      onOpenChange={(isOpen: boolean) => setOpenedDropdown(isOpen ? dropdownId : undefined)}
227	                      toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
228	                        <MenuToggle
229	                          id={`${dropdownId}-toggle`}
230	                          data-test={`${dropdownId}-toggle`}
231	                          ref={toggleRef}
232	                          className={`custom-chip ${filterValue.disabled ? 'disabled-value' : ''}`}
233	                          isExpanded={dropdownId === openedDropdown}
234	                          onClick={() => setOpenedDropdown(openedDropdown === dropdownId ? undefined : dropdownId)}
235	                        >
236	                          {filterValue.display ? filterValue.display : filterValue.v}
237	                        </MenuToggle>
238	                      )}
239	                    >
240	                      <DropdownList>
241	                        <DropdownItem
242	                          id="dropdown-item-edit"
243	                          data-test="dropdown-item-edit"
244	                          key="edit"
245	                          onClick={() => {
246	                            removeValue(filter, filterValue);
247	                            editValue(filter, filterValue.v);
248	                          }}
249	                        >
250	                          <PencilAltIcon />
251	                          &nbsp;{t('Edit')}
252	                        </DropdownItem>
253	                        {filters.match !== 'bidirectional' &&
254	                          (filter.def.id.startsWith('src_') || filter.def.id.startsWith('dst_')) && (
255	                            <DropdownItem
256	                              id="dropdown-item-either"
257	                              data-test="dropdown-item-either"
258	                              key="bnf"
259	                              onClick={() => {
260	                                const bnf = bnfFilterValue(
261	                                  filterDefinitions,
262	                                  filters!.list,
263	                                  filter.def.id,
264	                                  filterValue
265	                                );
266	                                setFilters({ ...filters!, list: bnf });
267	                                setOpenedDropdown(undefined);
268	                              }}
269	                            >
270	                              <ArrowsAltVIcon style={{ transform: 'rotate(90deg)' }} />
271	                              &nbsp;{t('Either')}
272	                            </DropdownItem>
273	                          )}
274	                        {(filter.def.category === 'endpoint' || filter.def.id.startsWith('dst_')) && (
275	                          <DropdownItem
276	                            id="dropdown-item-src"
277	                            data-test="dropdown-item-src"
278	                            key="src"
279	                            onClick={() => swapValue(filter, filterValue, 'src')}
280	                          >
281	                            <SourceIcon />
282	                            &nbsp;{filters.match === 'bidirectional' ? t('As endpoint A') : t('As source')}
283	                          </DropdownItem>
284	                        )}
285	                        {(filter.def.category === 'endpoint' || filter.def.id.startsWith('src_')) && (
286	                          <DropdownItem
287	                            id="dropdown-item-dst"
288	                            data-test="dropdown-item-dst"
289	                            key="dst"
290	                            onClick={() => swapValue(filter, filterValue, 'dst')}
291	                          >
292	                            <DestinationIcon />
293	                            &nbsp;{filters.match === 'bidirectional' ? t('As endpoint B') : t('As destination')}
294	                          </DropdownItem>
295	                        )}
296	                        <DropdownItem
297	                          id="dropdown-item-disable"
298	                          data-test="dropdown-item-disable"
299	                          key="disable"
300	                          onClick={() => {
301	                            filterValue.disabled = !filterValue.disabled;
302	                            setFilters(_.cloneDeep(filters));
303	                            setOpenedDropdown(undefined);
304	                          }}
305	                        >
306	                          {filterValue.disabled && <CheckIcon />}
307	                          {!filterValue.disabled && <BanIcon />}
308	                          &nbsp;{filterValue.disabled ? t('Enable') : t('Disable')}
309	                        </DropdownItem>
310	                        <DropdownItem
311	                          id="dropdown-item-remove"
312	                          data-test="dropdown-item-remove"
313	                          key="remove"
314	                          onClick={() => {
315	                            removeValue(filter, filterValue);
316	                          }}
317	                        >
318	                          <TimesIcon />
319	                          &nbsp;{t('Remove')}
320	                        </DropdownItem>
321	                      </DropdownList>
322	                    </Dropdown>
323	                  </div>
324	                );
325	              })}
326	            </div>
327	            {!isForced && (
328	              <Button
329	                icon={<TimesCircleIcon />}
330	                id="button-remove-filters"
331	                data-test="button-remove-filters"
332	                variant="plain"
333	                onClick={() => setFiltersList(removeFromFilters(filters.list, filter))}
334	              />
335	            )}
336	          </div>
337	        </div>
338	      );
339	    },
340	    // eslint-disable-next-line react-hooks/exhaustive-deps
341	    [filterDefinitions, filters, isForced, openedDropdown, setFilters, setFiltersList, swapValue]
342	  );
343	
344	  const setMatch = React.useCallback(
345	    (v: Match) => {
346	      const existingFilters = filters;
347	      // convert all endpoint filters to a single peer
348	      if (v == 'bidirectional') {
349	        existingFilters.list = setEndpointFilters(filterDefinitions, existingFilters.list, 'src');
350	        setDirection('source');
351	      }
352	      setFilters({ ...existingFilters, match: v });
353	    },
354	    [filters, setFilters, filterDefinitions, setDirection]
355	  );
356	
357	  const getAndOr = React.useCallback(
358	    (match: Match | 'values', index: number, root?: boolean) => {
359	      if (index == 0) {
360	        return undefined;
361	      }
362	
363	      return (
364	        <Tooltip
365	          content={
366	            match === 'values'
367	              ? t('the logical OR operator is used between each values of the same filter.')
368	              : match === 'any'
369	              ? t('The logical OR operator is used between filters.')
370	              : match === 'bidirectional'
371	              ? t(
372	                  'The logical AND operator is used between Endpoints and common filters. The traffic is matched in both directions.'
373	                )
374	              : t('The logical AND operator is used between filters keeping direction source to destination.')
375	          }
376	        >
377	          <div className="match-dropdown-container">
378	            {match === 'values' && (
379	              <Text className="and-or-text" component="p">
380	                {t('OR')}
381	              </Text>
382	            )}
383	            {match !== 'values' && (
384	              <MatchDropdown
385	                id={`match-${index}`}
386	                selected={filters.match}
387	                setMatch={setMatch}
388	                allowBidirectional={root && index === 1}
389	              />
390	            )}
391	          </div>
392	        </Tooltip>
393	      );
394	    },
395	    [filters.match, setMatch, t]
396	  );
397	
398	  if (_.isEmpty(filters.list) && _.isEmpty(getDefaultFilters())) {
399	    return null;
400	  }
401	  const isDefaultFilters = filtersEqual(filters.list, getDefaultFilters());
402	
403	  return (
404	    <>
405	      <ToolbarItem
406	        data-test={`${isForced ? 'forced-' : ''}filters`}
407	        id={`${isForced ? 'forced-' : ''}filters`}
408	        className="flex-start"
409	      >
410	        {getGroups()
411	          .filter(gp => gp.filters.length)
412	          .map((gp, index) => {
413	            return (
414	              <div key={gp.id} className="flex-block no-wrap">
415	                {getAndOr(filters.match, index, true)}
416	                <div className={`custom-chip-box ${gp.id !== 'common' ? 'custom-chip-peer' : ''}`}>
417	                  {hasSrcOrDstFilters(gp.filters) && (
418	                    <Text component="p">
419	                      {filters.match === 'bidirectional' ? (
420	                        <EndpointIcon />
421	                      ) : gp.id === 'src' ? (
422	                        <SourceIcon />
423	                      ) : gp.id === 'dst' ? (
424	                        <DestinationIcon />
425	                      ) : null}
426	                      &nbsp;{getGroupName(gp.id)}&nbsp;
427	                    </Text>
428	                  )}
429	                  <div className="flex-block">{gp.filters.map(getFilterDisplay)}</div>
430	                </div>
431	              </div>
432	            );
433	          })}
434	      </ToolbarItem>
435	      <ToolbarItem className="flex-start toolbar-item-center">
436	        {isForced ? (
437	          <Button
438	            id="edit-filters-button"
439	            data-test="edit-filters-button"
440	            onClick={() => navigate(getPathWithParams(netflowTrafficPath))}
441	          >
442	            {t('Edit filters')}
443	          </Button>
444	        ) : (
445	          <LinksOverflow
446	            id={'chips-more-options'}
447	            items={[
448	              {
449	                id: 'reset-filters',
450	                label: t('Reset defaults'),
451	                onClick: () => {
452	                  resetFilters();
453	                  autoCompleteCache.clear();
454	                },
455	                enabled: getDefaultFilters().length > 0 && !isDefaultFilters
456	              },
457	              {
458	                id: 'clear-all-filters',
459	                label: t('Clear all'),
460	                onClick: () => {
461	                  clearFilters();
462	                  autoCompleteCache.clear();
463	                },
464	                enabled: !_.isEmpty(filters.list)
465	              },
466	              {
467	                id: 'swap-filters',
468	                label: t('Swap'),
469	                tooltip: t('Swap from and to filters'),
470	                onClick: swapAllSrcDst,
471	                enabled: hasSrcOrDstFilters(filters.list!) && filters.match !== 'bidirectional'
472	              }
473	            ]}
474	            text={t('More actions')}
475	          />
476	        )}
477	      </ToolbarItem>
478	    </>
479	  );
480	};

